import{_ as n,c as t,o as i,a1 as a}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"Fortgeschritten: KI-Workflows | oh-my-opencode","description":"Meistern Sie die fortgeschrittene KI-Workflow-Orchestrierung in oh-my-opencode. Lernen Sie Agententeams, parallele Aufgaben, Kategorien/Fähigkeiten-System, Lifecycle-Hooks und tiefe Anpassungen, um effiziente KI-gestützte Entwicklungssysteme zu erstellen.","frontmatter":{"title":"Fortgeschritten: KI-Workflows | oh-my-opencode","sidebarTitle":"Arbeiten wie ein Team","subtitle":"Fortgeschritten: KI-Workflows","description":"Meistern Sie die fortgeschrittene KI-Workflow-Orchestrierung in oh-my-opencode. Lernen Sie Agententeams, parallele Aufgaben, Kategorien/Fähigkeiten-System, Lifecycle-Hooks und tiefe Anpassungen, um effiziente KI-gestützte Entwicklungssysteme zu erstellen.","order":60},"headers":[],"relativePath":"de/code-yeongyu/oh-my-opencode/advanced/index.md","filePath":"de/code-yeongyu/oh-my-opencode/advanced/index.md"}'),r={name:"de/code-yeongyu/oh-my-opencode/advanced/index.md"};function s(o,e,l,u,d,g){return i(),t("div",null,[...e[0]||(e[0]=[a(`<h1 id="fortgeschritten" tabindex="-1">Fortgeschritten <a class="header-anchor" href="#fortgeschritten" aria-label="Permalink to &quot;Fortgeschritten&quot;">​</a></h1><p>Dieses Kapitel taucht tief in die fortgeschrittenen Funktionen von oh-my-opencode ein: professionelle KI-Agententeams, parallele Hintergrundaufgaben, Kategorien- und Fähigkeiten-System, Lifecycle-Hooks und mehr. Das Beherrschen dieser Fähigkeiten ermöglicht es Ihnen, KI-Workflows zu orchestrieren wie die Verwaltung eines echten Teams und eine effizientere Entwicklungserfahrung zu erreichen.</p><h2 id="kapitelinhalt" tabindex="-1">Kapitelinhalt <a class="header-anchor" href="#kapitelinhalt" aria-label="Permalink to &quot;Kapitelinhalt&quot;">​</a></h2><div class="grid-cards"><h3 id="ki-agententeams-uberblick-uber-10-experten" tabindex="-1"><a href="./ai-agents-overview/">KI-Agententeams: Überblick über 10 Experten</a> <a class="header-anchor" href="#ki-agententeams-uberblick-uber-10-experten" aria-label="Permalink to &quot;[KI-Agententeams: Überblick über 10 Experten](./ai-agents-overview/)&quot;">​</a></h3><p>Umfassende Einführung in die Funktionalität, Anwendungsfälle und Aufrufmethoden von 10 integrierten Agenten. Lernen Sie, den richtigen Agenten basierend auf dem Aufgabentyp auszuwählen, was eine effiziente Teamzusammenarbeit, parallele Aufgabenausführung und tiefe Codeanalyse ermöglicht.</p><h3 id="prometheus-planung-interview-basierte-anforderungsermittlung" tabindex="-1"><a href="./prometheus-planning/">Prometheus-Planung: Interview-basierte Anforderungsermittlung</a> <a class="header-anchor" href="#prometheus-planung-interview-basierte-anforderungsermittlung" aria-label="Permalink to &quot;[Prometheus-Planung: Interview-basierte Anforderungsermittlung](./prometheus-planning/)&quot;">​</a></h3><p>Klären Sie Anforderungen und erstellen Sie Arbeitspläne durch den Interview-Modus. Prometheus wird weiterhin Fragen stellen, bis die Anforderungen klar sind, und konsultiert automatisch Oracle, Metis und Momus, um die Planqualität zu verifizieren.</p><h3 id="hintergrund-parallelaufgaben-arbeiten-wie-ein-team" tabindex="-1"><a href="./background-tasks/">Hintergrund-Parallelaufgaben: Arbeiten wie ein Team</a> <a class="header-anchor" href="#hintergrund-parallelaufgaben-arbeiten-wie-ein-team" aria-label="Permalink to &quot;[Hintergrund-Parallelaufgaben: Arbeiten wie ein Team](./background-tasks/)&quot;">​</a></h3><p>Umfassende Erklärung der Verwendung des Hintergrund-Agentenmanagementsystems. Lernen Sie Parallelitätssteuerung, Aufgabenabfrage und Ergebniserfassung, wodurch mehrere KI-Agenten gleichzeitig verschiedene Aufgaben bewältigen können, was die Arbeitseffizienz drastisch verbessert.</p><h3 id="lsp-und-ast-grep-code-refactoring-tools" tabindex="-1"><a href="./lsp-ast-tools/">LSP und AST-Grep: Code-Refactoring-Tools</a> <a class="header-anchor" href="#lsp-und-ast-grep-code-refactoring-tools" aria-label="Permalink to &quot;[LSP und AST-Grep: Code-Refactoring-Tools](./lsp-ast-tools/)&quot;">​</a></h3><p>Einführung in die Verwendung von LSP-Tools und AST-Grep-Tools. Zeigen Sie, wie Sie IDE-level Codeanalyse und -operationen implementieren, einschließlich Symbolnavigation, Referenzsuche und strukturierter Codesuche.</p><h3 id="kategorien-und-fahigkeiten-dynamische-agentenzusammensetzung" tabindex="-1"><a href="./categories-skills/">Kategorien und Fähigkeiten: Dynamische Agentenzusammensetzung</a> <a class="header-anchor" href="#kategorien-und-fahigkeiten-dynamische-agentenzusammensetzung" aria-label="Permalink to &quot;[Kategorien und Fähigkeiten: Dynamische Agentenzusammensetzung](./categories-skills/)&quot;">​</a></h3><p>Lernen Sie, das Kategorien- und Fähigkeiten-System zu verwenden, um spezialisierte Unteragenten zu erstellen. Implementieren Sie flexible Agentenzusammensetzung, dynamische Zuweisung von Modellen, Tools und Fähigkeiten basierend auf Aufgabenanforderungen.</p><h3 id="integrierte-fahigkeiten-browser-automatisierung-und-git-experte" tabindex="-1"><a href="./builtin-skills/">Integrierte Fähigkeiten: Browser-Automatisierung und Git-Experte</a> <a class="header-anchor" href="#integrierte-fahigkeiten-browser-automatisierung-und-git-experte" aria-label="Permalink to &quot;[Integrierte Fähigkeiten: Browser-Automatisierung und Git-Experte](./builtin-skills/)&quot;">​</a></h3><p>Detaillierte Einführung in die Anwendungsfälle und Best Practices von drei integrierten Fähigkeiten (playwright, frontend-ui-ux, git-master). Schneller Zugriff auf professionelle Fähigkeiten wie Browser-Automatisierung, Frontend-UI-Design und Git-Operationen.</p><h3 id="lifecycle-hooks-automatisierter-kontext-und-qualitatskontrolle" tabindex="-1"><a href="./lifecycle-hooks/">Lifecycle-Hooks: Automatisierter Kontext und Qualitätskontrolle</a> <a class="header-anchor" href="#lifecycle-hooks-automatisierter-kontext-und-qualitatskontrolle" aria-label="Permalink to &quot;[Lifecycle-Hooks: Automatisierter Kontext und Qualitätskontrolle](./lifecycle-hooks/)&quot;">​</a></h3><p>Einführung in die Verwendung von 32 Lifecycle-Hooks. Verstehen Sie, wie Sie Kontextinjektion, Fehlerwiederherstellung und Qualitätskontrolle automatisieren und ein vollständiges KI-Workflow-Automatisierungssystem erstellen.</p><h3 id="slash-befehle-voreingestellte-workflows" tabindex="-1"><a href="./slash-commands/">Slash-Befehle: Voreingestellte Workflows</a> <a class="header-anchor" href="#slash-befehle-voreingestellte-workflows" aria-label="Permalink to &quot;[Slash-Befehle: Voreingestellte Workflows](./slash-commands/)&quot;">​</a></h3><p>Einführung in die Verwendung von 6 integrierten Slash-Befehlen. Einschließlich /ralph-loop (Schnellkorrektur-Schleife), /refactor (Code-Refactoring), /start-work (Projektausführung starten) und andere häufige Workflows.</p><h3 id="konfigurationstiefe-anpassung-agenten-und-berechtigungsverwaltung" tabindex="-1"><a href="./advanced-configuration/">Konfigurationstiefe Anpassung: Agenten- und Berechtigungsverwaltung</a> <a class="header-anchor" href="#konfigurationstiefe-anpassung-agenten-und-berechtigungsverwaltung" aria-label="Permalink to &quot;[Konfigurationstiefe Anpassung: Agenten- und Berechtigungsverwaltung](./advanced-configuration/)&quot;">​</a></h3><p>Lehren Sie Benutzern die tiefe Anpassung der Agentenkonfiguration, Berechtigungseinstellungen, Modellüberschreibungen und Prompt-Modifikationen. Meistern Sie vollständige Konfigurationsfähigkeiten und erstellen Sie KI-Workflows, die mit Teamstandards übereinstimmen.</p></div><h2 id="lernpfad" tabindex="-1">Lernpfad <a class="header-anchor" href="#lernpfad" aria-label="Permalink to &quot;Lernpfad&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  Schritt 1                  Schritt 2                     Schritt 3                          Schritt 4                  │</span></span>
<span class="line"><span>│  KI-Agenten verstehen  →   Planung meistern    →   Dynamische Agenten     →   Tiefe Anpassung       │</span></span>
<span class="line"><span>│  (Grundkonzepte)          &amp; Parallele Aufgaben         Zusammensetzung           &amp; Automatisierung          │</span></span>
<span class="line"><span>│                                                      (Fortgeschrittene Nutzung)          (Expertenstufe)           │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────────────────────────────────────────────────────┘</span></span></code></pre></div><p><strong>Empfohlene Reihenfolge</strong>:</p><ol><li><strong>Beginnen Sie mit KI-Agententeams</strong>: Verstehen Sie die Verantwortlichkeiten und Anwendungsfälle von 10 Agenten – dies ist der Eckstein für das Verständnis des gesamten Systems.</li><li><strong>Dann lernen Sie Planung und Parallele Aufgaben</strong>: Meistern Sie Prometheus-Planung und das Hintergrundaufgabensystem – dies ist der Kern der effizienten Zusammenarbeit.</li><li><strong>Als Nächstes lernen Sie Dynamische Agentenzusammensetzung</strong>: Lernen Sie Kategorien und Fähigkeiten, um flexible Agentenspezialisierung zu erreichen.</li><li><strong>Schließlich lernen Sie Tiefe Anpassung</strong>: Meistern Sie Lifecycle-Hooks, Slash-Befehle und Konfigurationsanpassung, um vollständige Workflows zu erstellen.</li></ol><p><strong>Fortgeschrittene Routen</strong>:</p><ul><li>Wenn Ihr Ziel <strong>schneller Start</strong> ist: Konzentrieren Sie sich auf &quot;KI-Agententeams&quot; und &quot;Slash-Befehle&quot;</li><li>Wenn Ihr Ziel <strong>Teamzusammenarbeit</strong> ist: Tauchen Sie tief in &quot;Prometheus-Planung&quot; und &quot;Hintergrund-Parallelaufgaben&quot; ein</li><li>Wenn Ihr Ziel <strong>Workflow-Automatisierung</strong> ist: Lernen Sie &quot;Lifecycle-Hooks&quot; und &quot;Konfigurationstiefe Anpassung&quot;</li></ul><h2 id="voraussetzungen" tabindex="-1">Voraussetzungen <a class="header-anchor" href="#voraussetzungen" aria-label="Permalink to &quot;Voraussetzungen&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Bevor Sie beginnen</p><p>Dieses Kapitel setzt voraus, dass Sie Folgendes abgeschlossen haben:</p><ul><li>✅ <a href="/docs/opencodedocs/de/code-yeongyu/oh-my-opencode/start/installation/">Schnelle Installation und Konfiguration</a>: oh-my-opencode installiert und mindestens einen Provider konfiguriert</li><li>✅ <a href="/docs/opencodedocs/de/code-yeongyu/oh-my-opencode/start/sisyphus-orchestrator/">Erster Blick auf Sisyphus: Haupt-Orchestrator</a>: Grundlegende Agentenaufruf- und Delegationsmechanismen verstanden</li><li>✅ <a href="/docs/opencodedocs/de/code-yeongyu/oh-my-opencode/platforms/provider-setup/">Provider-Konfiguration: Claude, OpenAI, Gemini</a>: Mindestens einen KI-Provider konfiguriert</li></ul></div><h2 id="nachste-schritte" tabindex="-1">Nächste Schritte <a class="header-anchor" href="#nachste-schritte" aria-label="Permalink to &quot;Nächste Schritte&quot;">​</a></h2><p>Nach Abschluss dieses Kapitels empfehlen wir, fortzufahren mit:</p><ul><li><strong><a href="/docs/opencodedocs/de/code-yeongyu/oh-my-opencode/faq/troubleshooting/">Konfigurationsdiagnose und Fehlerbehebung</a></strong>: Schnelles Auffinden und Beheben von Problemen, wenn sie auftreten.</li><li><strong><a href="/docs/opencodedocs/de/code-yeongyu/oh-my-opencode/appendix/configuration-reference/">Konfigurationsreferenz</a></strong>: Vollständiges Konfigurationsdatei-Schema anzeigen und alle Konfigurationsoptionen verstehen.</li><li><strong><a href="/docs/opencodedocs/de/code-yeongyu/oh-my-opencode/appendix/claude-code-compatibility/">Claude Code Kompatibilität</a></strong>: Lernen Sie, wie Sie vorhandene Claude Code-Workflows zu oh-my-opencode migrieren.</li></ul>`,15)])])}const f=n(r,[["render",s]]);export{c as __pageData,f as default};
